import{_ as t,a as o,b as a,c as d,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as i}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as c,o as s,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"hi/Other/ocr.md","filePath":"hi/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"hi/Other/ocr.md"};function u(h,e,g,m,b,y){return s(),n("div",null,[...e[0]||(e[0]=[l('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR images, scans और document screenshots से text extract करता है।</p><p>Recognition के बाद आप result copy कर सकते हैं, उसे <code>Markdown</code>, <code>PDF</code> या <code>Word</code> के रूप में export कर सकते हैं, या multiple formats को साथ package करके download कर सकते हैं।</p><h2 id="ocr-क्या-कर-सकता-है" tabindex="-1">OCR क्या कर सकता है <a class="header-anchor" href="#ocr-क्या-कर-सकता-है" aria-label="Permalink to &quot;OCR क्या कर सकता है&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Image text recognition</td><td>Images, screenshots और scans से text extract करता है।</td></tr><tr><td>Document layout recognition</td><td>Tables, formulas, stamps और mixed text-image layouts के लिए बेहतर।</td></tr><tr><td>Multiple services</td><td>Baidu PaddleOCR, Microsoft Azure Vision और Google Vision support करता है।</td></tr><tr><td>Copy results</td><td>Processing के बाद recognized text copy करें।</td></tr><tr><td>Export files</td><td><code>Markdown</code>, <code>PDF</code> और <code>Word</code> export करें।</td></tr><tr><td>Batch packaging</td><td>Multiple files recognize करने के बाद results को package के रूप में download करें।</td></tr></tbody></table><h2 id="पहले-ocr-services-configure-करें" tabindex="-1">पहले OCR Services Configure करें <a class="header-anchor" href="#पहले-ocr-services-configure-करें" aria-label="Permalink to &quot;पहले OCR Services Configure करें&quot;">​</a></h2><p>खोलें:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+t+'" alt="IP geolocation and OCR" loading="lazy"></p><p>जिन services को इस्तेमाल करना चाहते हैं उनके credentials भरें:</p><table tabindex="0"><thead><tr><th>Service</th><th>What To Enter</th><th>Best For</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>Recommended first choice। Documents, images, tables और mixed layouts के लिए अच्छा।</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> और <code>Azure Vision API Key</code></td><td>अगर आप पहले से Microsoft cloud services इस्तेमाल करते हैं तो useful।</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>। Service account <code>JSON</code> केवल quota query के लिए इस्तेमाल होता है।</td><td>अगर आप Google Cloud services इस्तेमाल करते हैं तो useful।</td></tr></tbody></table><p>Credentials भरने के बाद save करें।</p><p>Initial testing के लिए केवल एक service configure करना काफी है। तीनों की ज़रूरत नहीं।</p><h2 id="google-vision-setup" tabindex="-1">Google Vision Setup <a class="header-anchor" href="#google-vision-setup" aria-label="Permalink to &quot;Google Vision Setup&quot;">​</a></h2><p>Google setup के दो हिस्से हैं:</p><table tabindex="0"><thead><tr><th>Goal</th><th>Requirement</th></tr></thead><tbody><tr><td>OCR इस्तेमाल करना</td><td><code>Cloud Vision API</code> enable करें, फिर <code>API Key</code> बनाएं।</td></tr><tr><td>Usage query करना</td><td>Service account बनाएं, <code>Monitoring Viewer</code> दें, फिर service account <code>JSON</code> download करें।</td></tr></tbody></table><p><img src="'+i+'" alt="Google API key and service account" loading="lazy"></p><h3 id="ocr-के-लिए-google-इस्तेमाल-करना" tabindex="-1">OCR के लिए Google इस्तेमाल करना <a class="header-anchor" href="#ocr-के-लिए-google-इस्तेमाल-करना" aria-label="Permalink to &quot;OCR के लिए Google इस्तेमाल करना&quot;">​</a></h3><ol><li>Google Cloud Console खोलें।</li><li><code>APIs &amp; Services</code> पर जाएँ।</li><li><code>Library</code> खोलें, <code>Cloud Vision API</code> search करें और enable करें।</li><li><code>Credentials</code> पर वापस जाएँ।</li><li>एक <code>API Key</code> create करें।</li><li>API Key खोलकर copy करें।</li><li>ImgBed के <code>Google Vision API Key</code> में paste करें।</li><li>Save करें।</li></ol><p>इसके बाद OCR dialog में Google Vision चुन सकते हैं।</p><h3 id="google-usage-query-करना" tabindex="-1">Google Usage Query करना <a class="header-anchor" href="#google-usage-query-करना" aria-label="Permalink to &quot;Google Usage Query करना&quot;">​</a></h3><p>Quota query recognition के लिए required नहीं है।</p><p>यह केवल roughly दिखाता है कि पिछले 30 दिनों में कितनी Google Vision calls इस्तेमाल हुईं।</p><ol><li>Google Cloud Console में <code>IAM &amp; Admin</code> खोलें।</li><li><code>Service Accounts</code> खोलें।</li><li>एक service account बनाएं, जैसे <code>vision-monitor</code>।</li><li>उसे <code>Monitoring Viewer</code> role दें।</li><li>Service account details खोलें और key create करें।</li><li><code>JSON</code> चुनें।</li><li>Generated JSON file download करें।</li><li>ImgBed पर लौटें और service account <code>JSON</code> के तहत इसे import करें (optional)।</li><li>Import successful होने के बाद quota query click करें।</li></ol><p>Import के बाद ImgBed service account वाला project name दिखाता है। Usage query करते समय ImgBed Google monitoring data पढ़कर इस महीने का call count दिखाता है।</p><p>संक्षेप में:</p><table tabindex="0"><thead><tr><th>Item</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>OCR recognition करता है।</td></tr><tr><td>Service account <code>JSON</code></td><td>Google Vision calls की usage query करता है।</td></tr><tr><td><code>Monitoring Viewer</code> role</td><td>Service account को usage data पढ़ने देता है।</td></tr></tbody></table><h2 id="baidu-paddleocr-token-लेना" tabindex="-1">Baidu PaddleOCR Token लेना <a class="header-anchor" href="#baidu-paddleocr-token-लेना" aria-label="Permalink to &quot;Baidu PaddleOCR Token लेना&quot;">​</a></h2><p>Baidu PaddleOCR को access token चाहिए।</p><p><img src="'+o+'" alt="Get PaddleOCR token" loading="lazy"></p><p>Baidu PaddleOCR page पर <code>API</code> call window खोलें, token लेने के लिए click करें, फिर उसे copy करें।</p><p>ImgBed पर लौटें, <code>PaddleOCR Token</code> में paste करें और save करें।</p><h2 id="recognition-शुरू-करना" tabindex="-1">Recognition शुरू करना <a class="header-anchor" href="#recognition-शुरू-करना" aria-label="Permalink to &quot;Recognition शुरू करना&quot;">​</a></h2><p>File Management में image या document screenshot select करें और <code>OCR</code> click करें।</p><p><img src="'+a+'" alt="OCR recognition" loading="lazy"></p><p>Dialog में recognition service और model चुनें।</p><p>Common PaddleOCR model choices:</p><table tabindex="0"><thead><tr><th>Model</th><th>Best For</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>Recommended default। Documents, tables, formulas, stamps और mixed layouts के लिए अच्छा।</td></tr><tr><td><code>PP-OCRv5</code></td><td>Simple images, ordinary text और lightweight recognition।</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>Multilingual, complex images और chart-like content।</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>ज़्यादा complex document pages और layout recovery।</td></tr></tbody></table><p>अगर unsure हैं, तो <code>PP-StructureV3</code> से शुरू करें।</p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Orientation correction</td><td>Image rotated या skewed हो तो इस्तेमाल करें।</td></tr><tr><td>Document flattening</td><td>Curvature या tilt वाले photographed documents के लिए इस्तेमाल करें।</td></tr><tr><td>Layout detection</td><td>Headings, paragraphs, tables और image structure preserve करना हो तो इस्तेमाल करें।</td></tr><tr><td>Chart recognition</td><td>Image में charts या complex structures हों तो इस्तेमाल करें।</td></tr><tr><td>Beautify <code>Markdown</code></td><td>Exported Markdown को पढ़ने में आसान बनाता है।</td></tr></tbody></table><p>Regular screenshots के लिए options minimal रखें। Document scans के लिए document-related options ज़्यादा enable करें।</p><h2 id="results-देखना" tabindex="-1">Results देखना <a class="header-anchor" href="#results-देखना" aria-label="Permalink to &quot;Results देखना&quot;">​</a></h2><p>Recognition finish होने के बाद dialog result दिखाता है।</p><p>आप इसे directly copy कर सकते हैं या export formats चुन सकते हैं।</p><p><img src="'+d+'" alt="PDF recognition" loading="lazy"></p><p>Document pages के लिए exported <code>PDF</code> page appearance preserve कर सकता है और text searchable रखता है। यह scans archive करने और बाद में content खोजने में उपयोगी है।</p><h2 id="export-format-चुनना" tabindex="-1">Export Format चुनना <a class="header-anchor" href="#export-format-चुनना" aria-label="Permalink to &quot;Export Format चुनना&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Best For</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>Notes, documentation systems और बाद की editing।</td></tr><tr><td><code>PDF (.pdf)</code></td><td>Page appearance और scanned document results preserve करना।</td></tr><tr><td><code>Word (.docx)</code></td><td>Layout editing, text modification और दूसरों को handoff।</td></tr><tr><td>Export all</td><td>Multiple formats और original image save करता है, important archives के लिए suitable।</td></tr></tbody></table><p>अगर सिर्फ text चाहिए, तो Markdown export करें।</p><p>अगर page appearance चाहिए, तो PDF या Word इस्तेमाल करें।</p><h2 id="word-output" tabindex="-1">Word Output <a class="header-anchor" href="#word-output" aria-label="Permalink to &quot;Word Output&quot;">​</a></h2><p>Exported Word documents office software में खोले और edit किए जा सकते हैं।</p><p><img src="'+r+`" alt="Word result" loading="lazy"></p><p>कुछ documents में Word output के अंदर recognized images, headings और paragraphs शामिल होते हैं।</p><p>Recognition quality original image clarity, model choice और document complexity पर depend करती है।</p><h2 id="ocr-के-लिए-best-file-types" tabindex="-1">OCR के लिए Best File Types <a class="header-anchor" href="#ocr-के-लिए-best-file-types" aria-label="Permalink to &quot;OCR के लिए Best File Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File Type</th><th>Recommendation</th></tr></thead><tbody><tr><td>Clear screenshots</td><td>Direct recognize करें।</td></tr><tr><td>Scans</td><td><code>PP-StructureV3</code> prefer करें।</td></tr><tr><td>Photographed documents</td><td>Orientation correction और document flattening enable करें।</td></tr><tr><td>Tables, formulas, stamps</td><td>Structured models prefer करें।</td></tr><tr><td>Simple short text images</td><td><code>PP-OCRv5</code> आम तौर पर काफी है।</td></tr></tbody></table><p>Straight text वाली clearer images बेहतर results देती हैं।</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Recognition fail होता है</td><td>Check करें कि service token या key save है।</td></tr><tr><td>Recognition slow है</td><td>Complex documents और large images में ज़्यादा समय लगता है।</td></tr><tr><td>Table incomplete है</td><td>Structured model try करें।</td></tr><tr><td>Text में mistakes हैं</td><td>Blur, glare और skew recognition errors बढ़ाते हैं। Clearer image try करें।</td></tr><tr><td>Word output में बहुत images हैं</td><td>Structured models कुछ recognized images preserve कर सकते हैं। यह normal है।</td></tr></tbody></table><h3 id="google-quota-query-fail-हो-रही-है" tabindex="-1">Google Quota Query fail हो रही है <a class="header-anchor" href="#google-quota-query-fail-हो-रही-है" aria-label="Permalink to &quot;Google Quota Query fail हो रही है&quot;">​</a></h3><p>Check करें:</p><ol><li>Service account <code>JSON</code> import हुआ है।</li><li>Service account के पास <code>Monitoring Viewer</code> role है।</li><li>Project में <code>Cloud Vision API</code> enabled है।</li></ol><p>अगर आपको सिर्फ OCR चाहिए और usage query नहीं, तो service account JSON ignore कर सकते हैं और केवल <code>Google Vision API Key</code> भर सकते हैं।</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings खोलें</span></span>
<span class="line"><span>-&gt; Other Settings खोलें</span></span>
<span class="line"><span>-&gt; OCR service credentials भरें</span></span>
<span class="line"><span>-&gt; Save करें</span></span>
<span class="line"><span>-&gt; File Management पर लौटें</span></span>
<span class="line"><span>-&gt; File select करें और OCR click करें</span></span>
<span class="line"><span>-&gt; Model चुनें</span></span>
<span class="line"><span>-&gt; Recognition का इंतज़ार करें</span></span>
<span class="line"><span>-&gt; Results copy करें या Markdown / PDF / Word export करें</span></span></code></pre></div>`,67)])])}const v=c(p,[["render",u]]);export{C as __pageData,v as default};
